setCps(220/60/4);

/* ----------------------------------------------------
   0. Masks & arrangement timeline
---------------------------------------------------- */
var bassMask     = "<0!8 1>";      // Bass enters after 8 cycles
var padMask      = "<0!16 1>";     // Pads fade in after 16 cycles
var leadMask     = "<0!32 1>";     // Melody enters halfway
var fxMask       = "<0!4 1>";      // Texture starts after 4
var vocalMask    = "<0!48 1>";     // Vocoder textures late
var outroMask    = "<1!24 0!16 1>"; // Slow fade out

/* ----------------------------------------------------
   1. Percussion – kick + minimal groove
---------------------------------------------------- */
$: s("bd!2 mt ~").bank("tr909").gain(0.5).off(1/4, x=>x).gain(.39)._pianoroll();//.swing("<0 0 1 1 1 2 1 2>");
//$: s("hh*16").bank("tr909").gain(0.125).swing(4);
$: s("~ cp(2,8)").gain(.38).bank("tr909").off(1/32, x=>x);

/* ----------------------------------------------------
   2. Sub Bass – steady C minor root
---------------------------------------------------- */
var bassFreq = saw.slow(2).rangex(120, 2400);
$: note("c1!4 c1!4 c1!4 c1!4 ").sound("sine")
  .gain(0.5).lpf(bassFreq)
  .decay(1).release(.5)
  //.mask(bassMask);

/* ----------------------------------------------------
   2. Sub Bass – глубокий, слышимый
---------------------------------------------------- */
var bassFreq = saw.slow(32).rangex(800, 1600); // ниже частота фильтра
$: note("[c4 ab0 bb0 g0]*1")               // немного хроматики
  .sound("gm_electric_bass_finger")
  .gain(0.41)                                // громче
  .lpf(bassFreq)
  .decay(1.4).release(.8)
 // .mask(bassMask);

/* ----------------------------------------------------
   3. Ambient Pad Chords – minor atmosphere
---------------------------------------------------- */
$: chord("<Am Dm Em C -!2>").voicing()
  .struct("[x y 1 2 a b x] - [~ x ~] [x ~ ~]")
  .sound("gm_acoustic_guitar_nylon")
  .gain(0.2214)
  .room(0.7).rsize(2.4)
  .delay(0.525).hush()
  //.mask(padMask);


$: 
note("<[c2 c3]*4 [ab1 ab2]*4 [bb2 bb3]*4 [g2 g3]*4>").color("cyan")
.sound("z_tan").lpf("<800 200 1200 400> 1000 200 400, 200 <400 2000>").gain(.9).pan(0.1) // .hush()
  
$: 
note("<[c2 c3]*4 [ab1 ab2]*4 [bb2 bb3]*4 [g2 g3]*4>").color("red")
.sound("z_square").lpf("<800 200 1200 400> 1000 200 400, 200 <400 2000>").gain(.9).rev().pan(0.9)

/* ----------------------------------------------------
   4. Lead melody – minimal drifting motif
---------------------------------------------------- */
$: n("<[0 3 7 4] <9 7 5 3>>").scale("C:minor:pentatonic")
  .sound("sawtooth")
  .adsr(".03:.2:.4:.3")
  .gain(0.12)
  .lpf(1500)
  .every(8, x => x.rev())
  .echo(2,1/6,.7)
.mask(leadMask).hush();

/* ----------------------------------------------------
   5. Textural FX – filtered noise & crackle
---------------------------------------------------- */
$: s("<z_noise ~ ~ ~>").gain("<.15 .2 .3 .2>")
  .lpf(sine.rangex(800, 10000))
  .delay(".25").delayfeedback(.4)
  .shape(.2)
  //.mask(fxMask);

$: s("crackle*16").density("0.01 0.03").gain(0.03).mask(fxMask);

/* ----------------------------------------------------
   6. Vocoder-esque shimmer accents
---------------------------------------------------- */
$: note("<[c4 ab4 eb4 g4 ~!4] ~!8 >").sound("pulse")
  .gain(0.05)
  .pw(".14").adsr(".02:.1:.6:.2")
  .lpf("<800 400>")//.rev.speed(-1)
  .echo(3,1/8,.6).gain(1) //.hush()
  //.mask(vocalMask);

/*---------------------------------------------------- */
$: note("<~!6 [c7 <~ ab7> eb7 <g7 ~>]!2 >").sound("sawtooth")
  .echo(3,1/8,.6).gain(0.13)

/* ----------------------------------------------------
   7. Mastering – soft pump & fade
---------------------------------------------------- */
all(x=>x.postgain(square.segment(64).range(0.9,1.1)));
// all(x=>x.gain(square.slow(64).rangex(.75,1)).mask(outroMask));

all(pianoroll())